def _provider(p: dict[str, Any], d: list[str], e: list[str]) -> DailyOperatorRunComponent:
    s = _as_dict(p.get("summary"))
    missing = _int(s.get("missing_secret_count")); action = _int(s.get("action_required_count")); stale = _int(s.get("stale_count")); not_checked = _int(s.get("not_checked_count")); blocked = _int(s.get("blocked_count")); count = _int(s.get("provider_count"))
    warnings = list(d); blockers = list(e); actions: list[str] = []
    if missing: actions.append("Configure missing provider env var names in a gitignored env file if those feeds are required.")
    if stale or not_checked: actions.append("Refresh provider samples or run provider ingestion before freshness-sensitive research.")
    if action: actions.append("Resolve provider key, plan, or rate-limit attention items before promotion evidence use.")
    if blocked: blockers.append("PROVIDER_POLICY_BLOCKERS_PRESENT")
    if count == 0: warnings.append("NO_PROVIDER_SETUP_ROWS")
    status = "BLOCKED" if blockers else "WARNING" if warnings or missing or action or stale or not_checked else "OK"
    return _component("provider_setup", "Provider setup and freshness", "/ui/provider-setup", status, "ACTION_REQUIRED" if missing or action else "STALE" if stale else "READY", {"provider_count": count, "ready_count": _int(s.get("ready_count")), "action_required_count": action, "blocked_count": blocked, "stale_count": stale, "not_checked_count": not_checked, "missing_secret_count": missing, "samples_manifest_path": p.get("samples_manifest_path")}, warnings, blockers, actions)


def _intake(p: dict[str, Any], d: list[str], e: list[str]) -> DailyOperatorRunComponent:
    latest = _as_dict(p.get("latest")); count = _int(latest.get("intake_count")); warnings = list(d); actions: list[str] = []
    if count == 0:
        warnings.append("NO_STRATEGY_INTAKES_READY"); actions.append("Submit or refresh a strategy intake before spending research batch budget.")
    return _component("strategy_intake", "Strategy intake inbox", "/ui/strategy-intake/latest", "BLOCKED" if e else "WARNING" if warnings else "OK", "EMPTY" if count == 0 else "READY", {"intake_count": count, "index_path": p.get("index_path"), "authority_boundary": p.get("authority_boundary")}, warnings, e, actions)


def _backtest(p: dict[str, Any], d: list[str], e: list[str]) -> DailyOperatorRunComponent:
    s = _as_dict(p.get("summary")); b = _as_dict(p.get("batch")); warnings = list(d); actions: list[str] = []
    strategy = _int(s.get("strategy_count")); needs = _int(s.get("needs_evidence_count")); paper = _int(s.get("paper_only_count")); blocked = _int(s.get("blocked_count")); failed = _int(s.get("failed_count"))
    if not s.get("batch_present"):
        warnings.append("NO_BACKTEST_BATCH_PRESENT"); actions.append("Run or import a strategy batch so forensic review has evidence to summarize.")
    if needs: actions.append("Attach missing robustness, PIT, execution-realism, or evidence-manifest artifacts.")
    if blocked or failed: actions.append("Review failed/blocked strategies before any validator adjudication.")
    if paper: actions.append("Treat paper-only rows as research evidence only; do not infer live readiness.")
    status = "BLOCKED" if e else "WARNING" if warnings or needs or paper or blocked or failed else "OK"
    return _component("backtest_forensics", "Backtest forensic review", "/ui/backtest-forensics/latest", status, "NO_BATCH" if not s.get("batch_present") else "NEEDS_EVIDENCE" if needs else "PAPER_ONLY" if paper else "REVIEW_READY", {"batch_present": bool(s.get("batch_present")), "batch_id": b.get("batch_id"), "run_id": b.get("run_id"), "strategy_count": strategy, "blocked_count": blocked, "needs_evidence_count": needs, "paper_only_count": paper, "failed_count": failed, "summary_path": p.get("summary_path")}, warnings, e, actions)


def _graveyard(p: dict[str, Any], d: list[str], e: list[str]) -> DailyOperatorRunComponent:
    s = _as_dict(p.get("summary")); hard = _int(s.get("hard_blocked_count")); cond = _int(s.get("conditional_retry_count")); dupe = _int(s.get("duplicate_superseded_count")); review = _int(s.get("operator_review_count")); warnings = list(d); actions: list[str] = []
    if hard: actions.append("Do not reopen hard-blocked strategies until resurrection evidence or governed exceptions exist.")
    if cond: actions.append("Select conditional retry candidates only after required evidence manifests are planned.")
    if dupe: actions.append("Keep duplicate variants superseded unless a material fingerprint difference is documented.")
    return _component("strategy_graveyard", "Strategy graveyard and resurrection rules", "/ui/strategy-graveyard/latest", "BLOCKED" if e else "WARNING" if warnings or hard or review else "OK", "HARD_BLOCKERS" if hard else "REVIEW_REQUIRED" if review else "TRACKING", {"entry_count": _int(s.get("entry_count")), "hard_blocked_count": hard, "conditional_retry_count": cond, "duplicate_superseded_count": dupe, "operator_review_count": review, "index_path": p.get("index_path")}, warnings, e, actions)


def _evidence(p: dict[str, Any], d: list[str], e: list[str]) -> DailyOperatorRunComponent:
    s = _as_dict(p.get("summary")); total = _int(s.get("event_count_total")); issues = _int(s.get("chain_issue_count_total")); warnings = list(d); blockers = list(e); actions: list[str] = []
    if issues or not bool(s.get("decision_ledger_chain_ok")) or not bool(s.get("operator_action_chain_ok")):
        blockers.append("EVIDENCE_CHAIN_NOT_VERIFIED"); actions.append("Inspect /ui/evidence-chain before trusting operator receipts or decision-ledger lineage.")
    if total == 0:
        warnings.append("NO_EVIDENCE_CHAIN_EVENTS"); actions.append("Run a decision or operator action flow to materialize verifiable evidence-chain events.")
    return _component("evidence_chain", "Evidence chain health", "/ui/evidence-chain", "BLOCKED" if blockers else "WARNING" if warnings else "OK", "CHAIN_ISSUES" if blockers else "EMPTY" if total == 0 else "VERIFIED", {"event_count_total": total, "chain_issue_count_total": issues, "decision_ledger_event_count": _int(s.get("decision_ledger_event_count")), "operator_action_event_count": _int(s.get("operator_action_event_count")), "decision_ledger_chain_ok": bool(s.get("decision_ledger_chain_ok")), "operator_action_chain_ok": bool(s.get("operator_action_chain_ok"))}, warnings, blockers, actions)


def _research(p: dict[str, Any], d: list[str], e: list[str]) -> DailyOperatorRunComponent:
    latest = _as_dict(p.get("latest")); steps = _as_list(latest.get("steps")); status_val = str(latest.get("status") or p.get("status") or "NOT_PRESENT"); warnings = list(d) + _strings(latest.get("warnings")); blockers = list(e) + _strings(latest.get("blockers")); actions: list[str] = []
    if not latest:
        warnings.append("NO_RESEARCH_OS_OPERATOR_RUN"); actions.append("Run strategy-validator-research-os-run run --overwrite --json to create a digest-linked operator-run manifest.")
    if status_val in {"BLOCKED", "FAILED"}: blockers.append(f"RESEARCH_OS_OPERATOR_RUN_{status_val}")
    if status_val != "COMPLETE": actions.append("Review Research OS run warnings before treating the daily briefing as complete.")
    return _component("research_os_operator_run", "Research OS operator-run manifest", "/ui/research-os/run/latest", "BLOCKED" if blockers else "WARNING" if warnings or status_val != "COMPLETE" else "OK", status_val, {"run_id": latest.get("run_id"), "status": status_val, "trust_banner": latest.get("trust_banner"), "step_count": len(steps), "manifest_path": p.get("manifest_path"), "manifest_sha256": latest.get("manifest_sha256")}, warnings, blockers, actions)


def _status(components: list[DailyOperatorRunComponent]) -> tuple[str, str]:
    if not components: return "EMPTY", "UNTRUSTED"
    if any(c.status == "BLOCKED" for c in components): return "BLOCKED", "UNTRUSTED"
    if any(c.status in {"WARNING", "NOT_PRESENT"} for c in components): return "RESTRICTED", "TRUST_RESTRICTED"
    return "COMPLETE", "TRUSTED"


