def build_ui_daily_operator_run_payload(*, repo_root: Path | None = None, database_path: str | None = None) -> dict[str, Any]:
    now = datetime.now(timezone.utc)
    pp, pd, pe = _safe("/ui/provider-setup", lambda: build_ui_provider_setup_payload(repo_root=repo_root, generated_at_utc=now))
    ip, idg, ie = _safe("/ui/strategy-intake/latest", lambda: build_ui_strategy_intake_latest_payload(repo_root=repo_root))
    bp, bd, be = _safe("/ui/backtest-forensics/latest", lambda: build_ui_backtest_forensics_latest_payload(repo_root=repo_root))
    gp, gd, ge = _safe("/ui/strategy-graveyard/latest", lambda: build_ui_strategy_graveyard_latest_payload(repo_root=repo_root))
    ep, ed, ee = _safe("/ui/evidence-chain", lambda: build_ui_evidence_chain_payload(database_path=database_path, readonly=True, limit=50))
    xp, xd, xe = _safe("/ui/paper-execution/latest", lambda: build_ui_paper_execution_cockpit_payload(repo_root=repo_root))
    rp, rd, re = _safe("/ui/research-os/run/latest", lambda: build_ui_research_os_operator_run_latest_payload(repo_root=repo_root))
    comps = [_provider(pp,pd,pe), _intake(ip,idg,ie), _backtest(bp,bd,be), _graveyard(gp,gd,ge), _evidence(ep,ed,ee), _paper_execution(xp,xd,xe), _research(rp,rd,re)]
    status, trust = _status(comps)
    warnings = sorted({f"{c.component_id}:{w}" for c in comps for w in c.warnings})
    blockers = sorted({f"{c.component_id}:{b}" for c in comps for b in c.blockers})
    actions = list(dict.fromkeys(a for c in comps for a in c.recommended_actions))
    if not actions and status == "COMPLETE": actions.append("Daily operator briefing is complete; continue monitoring projections and evidence freshness.")
    return DailyOperatorRunPayload(generated_at_utc=now, status=status, trust_banner=trust, summary=_summary(comps), components=comps, warnings=warnings, blockers=blockers, recommended_actions=actions, source_routes=[c.source_route for c in comps]).model_dump(mode="json")


__all__ = ["build_ui_daily_operator_run_payload"]
